import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Google Drive Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/google-drive.md","filePath":"ta/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"ta/upload/google-drive.md"};function c(p,e,h,g,u,m){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="google-drive-channel-சேர்க்கவும்" tabindex="-1">Google Drive Channel சேர்க்கவும் <a class="header-anchor" href="#google-drive-channel-சேர்க்கவும்" aria-label="Permalink to &quot;Google Drive Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="முதலில்-தேவையானவை" tabindex="-1">முதலில் தேவையானவை <a class="header-anchor" href="#முதலில்-தேவையானவை" aria-label="Permalink to &quot;முதலில் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>ஏன் தேவை</th></tr></thead><tbody><tr><td>Google account</td><td>Google Cloud அணுகவும் Google Drive authorize செய்யவும்</td></tr><tr><td>Google Cloud project</td><td>Drive API enable செய்து OAuth credentials உருவாக்க</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed <code>Client ID</code>, <code>Client Secret</code>, <code>Refresh Token</code> பெற</td></tr><tr><td>உங்கள் ImgBed domain</td><td>OAuth redirect URI-க்கு. நீங்கள் பயன்படுத்தும் domain-க்கு சரியாக match ஆக வேண்டும்.</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-google-drive-api-enable-செய்யவும்" tabindex="-1">Step 1: Google Drive API Enable செய்யவும் <a class="header-anchor" href="#step-1-google-drive-api-enable-செய்யவும்" aria-label="Permalink to &quot;Step 1: Google Drive API Enable செய்யவும்&quot;">​</a></h3><ol><li>Google Cloud Console திறக்கவும்.</li><li>புதிய project உருவாக்கவும் அல்லது existing project தேர்வு செய்யவும்.</li><li><code>APIs &amp; Services</code> செல்லவும்.</li><li><code>Enable APIs and Services</code> கிளிக் செய்யவும்.</li><li><code>Google Drive API</code> தேடவும்.</li><li>அதைத் திறந்து enable கிளிக் செய்யவும்.</li></ol><h3 id="step-2-oauth-consent-screen-configure-செய்யவும்" tabindex="-1">Step 2: OAuth Consent Screen Configure செய்யவும் <a class="header-anchor" href="#step-2-oauth-consent-screen-configure-செய்யவும்" aria-label="Permalink to &quot;Step 2: OAuth Consent Screen Configure செய்யவும்&quot;">​</a></h3><ol><li>Google Cloud-ல் <code>Google Auth Platform</code> திறக்கவும்.</li><li>app name, support email, developer contact email போன்ற basic <code>Branding</code> தகவலை முடிக்கவும்.</li><li><code>Audience</code> திறக்கவும்.</li><li>பெரும்பாலான self-hosted personal deployments-க்கு <code>External</code> தேர்வு செய்யவும்.</li><li><code>External</code> தேர்வு செய்தால் authorize செய்ய வேண்டிய Google account-ஐ <code>Test users</code>-ல் சேர்க்கவும்.</li><li><code>Data Access</code> திறக்கவும்.</li><li>தேவையான Google Drive permissions சேர்க்கவும்.</li></ol><h3 id="step-3-oauth-2-0-client-உருவாக்கவும்" tabindex="-1">Step 3: OAuth 2.0 Client உருவாக்கவும் <a class="header-anchor" href="#step-3-oauth-2-0-client-உருவாக்கவும்" aria-label="Permalink to &quot;Step 3: OAuth 2.0 Client உருவாக்கவும்&quot;">​</a></h3><ol><li><code>Google Auth Platform</code>-ல் <code>Clients</code> திறக்கவும்.</li><li>புதிய client உருவாக்கவும்.</li><li>application type-ஐ <code>Web application</code> ஆக அமைக்கவும்.</li><li>அறியக்கூடிய client name கொடுக்கவும்.</li><li>authorized JavaScript origins-ல் உங்கள் ImgBed URL கொடுக்கவும், உதா:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>authorized redirect URIs-ல்:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>client உருவான பிறகு:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-imgbed-ல்-google-drive-channel-நிரப்பவும்" tabindex="-1">Step 4: ImgBed-ல் Google Drive Channel நிரப்பவும் <a class="header-anchor" href="#step-4-imgbed-ல்-google-drive-channel-நிரப்பவும்" aria-label="Permalink to &quot;Step 4: ImgBed-ல் Google Drive Channel நிரப்பவும்&quot;">​</a></h2><p>Upload Settings-ல் <code>Google Drive</code> தேர்வு செய்து:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>அறியக்கூடிய பெயர், உதா. <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Google Cloud Client ID</td></tr><tr><td>Client Secret</td><td>Google Cloud Client Secret</td></tr><tr><td>Refresh Token</td><td>இப்போது காலியாக விடவும். அடுத்த step-ல் பெறவும்.</td></tr><tr><td>Root directory</td><td>Optional. default <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-refresh-token-பெறவும்" tabindex="-1">Step 5: Refresh Token பெறவும் <a class="header-anchor" href="#step-5-refresh-token-பெறவும்" aria-label="Permalink to &quot;Step 5: Refresh Token பெறவும்&quot;">​</a></h2><ol><li><code>Get Token</code> கிளிக் செய்யவும்.</li><li>connect செய்ய வேண்டிய Google account தேர்வு செய்யவும்.</li><li>authorization prompts முடிக்கவும்.</li><li>callback page <code>Refresh Token</code> காட்டும்.</li><li>அதை copy செய்யவும்.</li><li>ImgBed-க்கு திரும்பி <code>Refresh Token</code> field-ல் paste செய்யவும்.</li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>பின்னர் Google account மாற்றினாலும், OAuth client மாற்றினாலும், பழைய authorization expire ஆனாலும் channel delete செய்ய வேண்டியதில்லை. edit page திறந்து <code>Reauthorize</code> கிளிக் செய்யவும்.</p><h2 id="step-6-channel-save-செய்யவும்" tabindex="-1">Step 6: Channel Save செய்யவும் <a class="header-anchor" href="#step-6-channel-save-செய்யவும்" aria-label="Permalink to &quot;Step 6: Channel Save செய்யவும்&quot;">​</a></h2><p>அனைத்து fields நிரப்பிய பிறகு channel save செய்யவும்.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud திறக்கவும்</span></span>
<span class="line"><span>-&gt; project உருவாக்கவும் அல்லது தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; Google Drive API enable செய்யவும்</span></span>
<span class="line"><span>-&gt; Google Auth Platform configure செய்யவும்</span></span>
<span class="line"><span>-&gt; Audience External என்றால் Google account-ஐ Test users-ல் சேர்க்கவும்</span></span>
<span class="line"><span>-&gt; Web application OAuth client உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; redirect URI ஆக https://your-domain.com/api/oauth/google/callback பயன்படுத்தவும்</span></span>
<span class="line"><span>-&gt; Client ID மற்றும் Client Secret ImgBed-ல் நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Get Token கிளிக் செய்யவும்</span></span>
<span class="line"><span>-&gt; Google-ல் sign in செய்து authorize செய்யவும்</span></span>
<span class="line"><span>-&gt; callback page-ல் இருந்து Refresh Token copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் paste செய்து save செய்யவும்</span></span>
<span class="line"><span>-&gt; test image upload செய்யவும்</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,31)])])}const k=i(d,[["render",c]]);export{f as __pageData,k as default};
